    /// <summary>
    /// Gets the payout amount for a trip between two cities.
    /// </summary>
    /// <param name="fromPayoutIndex">PayoutIndex of the origin city.</param>
    /// <param name="toPayoutIndex">PayoutIndex of the destination city.</param>
    /// <returns>Payout amount in dollars.</returns>
    public static int GetPayout(int fromPayoutIndex, int toPayoutIndex)
    {
        if (fromPayoutIndex < 0 || fromPayoutIndex >= 28)
            throw new ArgumentOutOfRangeException(nameof(fromPayoutIndex), $"PayoutIndex must be between 0 and 27, got {fromPayoutIndex}.");
        if (toPayoutIndex < 0 || toPayoutIndex >= 28)
            throw new ArgumentOutOfRangeException(nameof(toPayoutIndex), $"PayoutIndex must be between 0 and 27, got {toPayoutIndex}.");

        return Payouts[fromPayoutIndex, toPayoutIndex];
    }
}
